{
  "sentences": [
    {
      "text": "你現在在做什麼？",
      "pinyin": "Nǐ xiànzài zài zuò shénme?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 zuo4 shen2me0",
      "translation_en": "What are you doing now?",
      "translation_ko": "지금 뭐 하고 있어요?"
    },
    {
      "text": "我正在看書。",
      "pinyin": "Wǒ zhèngzài kàn shū.",
      "pinyin_numeric": "wo3 zheng4zai4 kan4 shu1",
      "translation_en": "I am reading a book.",
      "translation_ko": "저는 책을 보고 있어요."
    },
    {
      "text": "他在上網嗎？",
      "pinyin": "Tā zài shàngwǎng ma?",
      "pinyin_numeric": "ta1 zai4 shang4wang3 ma0",
      "translation_en": "Is he surfing the internet?",
      "translation_ko": "그는 인터넷을 하고 있나요?"
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "我媽媽在煮飯。",
      "pinyin": "Wǒ māma zài zhǔ fàn.",
      "pinyin_numeric": "wo3 ma1ma0 zai4 zhu3 fan4",
      "translation_en": "My mom is cooking rice.",
      "translation_ko": "우리 엄마는 밥을 하고 있어요."
    },
    {
      "text": "你現在在忙嗎？",
      "pinyin": "Nǐ xiànzài zài máng ma?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 mang2 ma0",
      "translation_en": "Are you busy now?",
      "translation_ko": "지금 바쁘세요?"
    },
    {
      "text": "他正在開會，等一下回你。",
      "pinyin": "Tā zhèngzài kāihuì, děng yīxià huí nǐ.",
      "pinyin_numeric": "ta1 zheng4zai4 kai1hui4, deng3 yi1xia4 hui2 ni3",
      "translation_en": "He is in a meeting; he'll get back to you in a moment.",
      "translation_ko": "그는 회의 중이에요. 잠시 후에 답장할게요."
    },
    {
      "text": "我們在餐廳吃飯。",
      "pinyin": "Wǒmen zài cāntīng chī fàn.",
      "pinyin_numeric": "wo3men0 zai4 can1ting1 chi1 fan4",
      "translation_en": "We are eating at a restaurant.",
      "translation_ko": "우리는 식당에서 밥을 먹고 있어요."
    },
    {
      "text": "她正在寫功課，不方便講電話。",
      "pinyin": "Tā zhèngzài xiě gōngkè, bù fāngbiàn jiǎng diànhuà.",
      "pinyin_numeric": "ta1 zheng4zai4 xie3 gong1ke4, bu4 fang1bian4 jiang3 dian4hua4",
      "translation_en": "She is doing homework and can't talk on the phone.",
      "translation_ko": "그녀는 숙제를 하고 있어서 전화하기 어려워요."
    },
    {
      "text": "你哥哥在聽音樂嗎？",
      "pinyin": "Nǐ gēge zài tīng yīnyuè ma?",
      "pinyin_numeric": "ni3 ge1ge0 zai4 ting1 yin1yue4 ma0",
      "translation_en": "Is your older brother listening to music?",
      "translation_ko": "네 오빠는 음악을 듣고 있니?"
    }
  ]
}
